export function getProduct(id: string): Product | undefined {
  return products.find((p) => p.id === id)
}

export function getCategory(slug: string): Category | undefined {
  return categories.find((c) => c.slug === slug)
}

export function productsByCategory(categoryId: string): Product[] {
  return products.filter((p) => p.categoryId === categoryId)
}

/** URL de foto de stock para un producto (con palabra clave y semilla estable). */
export function productPhotoUrl(p: Product, variant = 0): string {
  const kw = p.photo || categoryPhoto[p.categoryId] || 'hardware,store'
  const seed = (Number(p.id.replace(/\D/g, '')) || 1) * 7 + variant
  return `https://loremflickr.com/600/450/${encodeURIComponent(kw)}?lock=${seed}`
}
